UPDATE /* PushMapper.sendPushSendResult */
NMCP_PUSH_SND_PROC_TRGT_LIST SET

    PROC_ST = #{procSt},

    SND_CNT = #{sndCnt},
    SND_PROC_DT = SYSDATE,
    SYS_CHG_DTIME = SYSDATE
WHERE 1=1
AND PUSH_SND_PROC_SNO = #{pushSndProcSno}
AND PUSH_SND_SET_SNO = #{pushSndSetSno}
AND USERID = #{userId}
